module RefModule(
    COUT,
    SUM ,
    A   ,
    B   ,
    CIN 
);output COUT;
    output SUM ;
    input  A   ;
    input  B   ;
    input  CIN ;

    wire w1, w2, w3;

    // XOR gates for SUM output
  assign COUT = w1 | w2 | w3;

    // AND gates for COUT output
  assign w3 = B & CIN;
  assign w2 = A & CIN;
  assign w1 = A & B;
  assign SUM = A ^ B ^ CIN;

endmodule
